import React from 'react';
import { useControlledState } from '@universe-design/react-utilities';
import { Select, Input, __SCREENSHOT__ } from '@universe-design/react';

const AutoComplete: React.FC<{
  defaultValue?: string;
  value?: string;
  onChange?: (v: string) => void;
}> = ({ defaultValue = '', value: valueProp, onChange }) => {
  const [inputValue, setInputValue] = useControlledState(defaultValue, valueProp, {
    onChange,
  });
  return (
    <Select
      defaultOpen={__SCREENSHOT__}
      searchValue={inputValue}
      value={undefined}
      triggerElement={({ inputRef, onInputChange, setOverlayVisible }) => (
        <div
          onMouseDown={ev => {
            console.log('onMouseDown bubbles', ev.target);
          }}
          onClick={ev => {
            setOverlayVisible();
            console.log('onClick bubbles', ev.target);
          }}
        >
          <Input.Search
            ref={inputRef as React.RefObject<HTMLInputElement>}
            value={inputValue}
            onChange={e => {
              onInputChange(e);
              setInputValue(e.target.value);
            }}
          />
        </div>
      )}
      options={[
        {
          value: 'Jack',
        },
        {
          value: 'Lucy',
        },
        {
          value: 'Tom',
        },
      ]}
    />
  );
};

export default () => <AutoComplete />;
